public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0;
    for (int right = 0; right < n; right++) {
        if (nums[right] == 5) {
            while (left < n && nums[left] != 4) {
                left++;
            }
            if (left != n) {
                int temp = nums[left + 1];
                nums[left + 1] = nums[right];
                nums[right] = temp;
            }
        }
    }
    return nums;
}

public int makeChocolate(int small, int big, int goal) {
    if (big * 5 >= goal) {
        if ((goal - big * 5) <= small) {
            return goal - big * 5;
        } else {
            return -1;
        }
    } else if (small >= goal) {
        return goal;
    } else {
        return -1;
    }
}

