public String plusOut(String str, String word) {
    String[] words = str.split(" ");
    StringBuilder sb = new StringBuilder();
    for (String s : words) {
        if (s.equals(word)) {
            sb.append(s);
        } else {
            sb.append("+");
            for (int i = 0; i < s.length(); i++) {
                sb.append("+");
            }
        }
        sb.append(" ");
    }
    return sb.toString().trim();
}

