    int bigUse = goal / 5;
    int smallUse = 0;
    if(bigUse <= big) {
        int remain = goal - bigUse * 5;
        if(remain <= small) {
            smallUse = remain;
        } else {
            smallUse = -1;
        }
    } else {
        smallUse = -1;
    }
    return smallUse;
}

