public boolean isEverywhere(int[] nums, int val) {
    if (nums.length == 0 || nums.length == 1) {
        return true;
    }

    for (int i = 0; i < nums.length - 1; i++) {
        if (nums[i] != val && nums[i + 1] != val) {
            return false;
        }
    }
    return true;
}

public String alarmClock(int day, boolean vacation) {
    if (day < 0 || day > 6) {
        return "Invalid day";
    }

    if (vacation) {
        if (day == 0 || day == 6) {
            return "off";
        } else {
            return "10:00";
        }
    } else {
        if (day == 0 || day == 6) {
            return "10:00";
        } else {
            return "7:00";
        }
    }
}

