public int sum67(int[] nums) {
    int sum = 0;
    boolean addToSum = true;

    for (int num : nums) {
        if (num == 6) {
            addToSum = false;
        } else if (num == 7) {
            addToSum = true;
        } else {
            if (addToSum) {
                sum += num;
            }
        }
    }

    return sum;
}

public String alarmClock(int day, boolean vacation) {
    if (day >= 0 && day <= 6) {
        if (vacation) {
            if (day == 0 || day == 6) {
                return "off";
            } else {
                return "10:00";
            }
        } else {
            if (day == 0 || day == 6) {
                return "10:00";
            } else {
