Code:
public String getSandwich(String str) {
    int firstBread = str.indexOf("bread");
    if (firstBread == -1) {
        return "";
    }
    int lastBread = str.lastIndexOf("bread");
    if (lastBread == -1 || lastBread == firstBread) {
        return "";
    }
    return str.substring(firstBread + 5, lastBread);
}

