Code:
public int[] zeroMax(int[] nums) {
    int n = nums.length;
    int[] maxOddToRight = new int[n];
    maxOddToRight[n - 1] = nums[n - 1] % 2 != 0 ? nums[n - 1] : -1;
    for (int i = n - 2; i >= 0; i--) {
        maxOddToRight[i] = nums[i] % 2 != 0 && nums[i] > maxOddToRight[i + 1] ? nums[i] : maxOddToRight[i + 1];
    }
    for (int i = 0; i < n; i++) {
        if (nums[i] == 0) {
            nums[i] = maxOddToRight[i];
        }
    }
    return nums;
}

