public int[] fix45(int[] nums) {
    Queue<Integer> queue = new LinkedList<>();
    Stack<Integer> stack = new Stack<>();
    for (int num : nums) {
        if (num == 4) {
            queue.offer(num);
        } else {
            stack.push(num);
        }
    }
    int[] res = new int[nums.length];
    int i = 0;
    while (!queue.isEmpty()) {
        res[i++] = queue.poll();
        if (!queue.isEmpty()) {
            res[i++] = queue.poll();
        }
        if (!stack.isEmpty()) {
            res[i++] = stack.pop();
        }
    }
    return res;
}

