public int[] seriesUp(int n) {
    if (n < 0) {
        throw new IllegalArgumentException("Input must be non-negative");
    }

    int size = n * (n + 1) / 2;
    int[] array = new int[size];
    int index = 0;

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            array[index++] = j;
        }
    }

    return array;
}

public boolean canBalance(int[] nums) {
    int numsSum = 0;
    for (int i = 0; i < nums.length; i++) {
        numsSum += nums[i];
    }
    int leftSum = 0;
    for (int i = 0; i < nums.length; i++) {
        numsSum -= nums[i];
        if (leftSum == numsSum) {
            return true;
        }
        leftSum += nums[i];
    }
    return false;
}

