public int[] shiftLeft(int[] nums) {
    int[] shifted = new int[nums.length];
    if (nums.length > 0) {
        for (int i = 0; i < nums.length - 1; i++) {
            shifted[i] = nums[i + 1];
        }
        shifted[nums.length - 1] = nums[0];
    }
    return shifted;
}

