    int baseSpeed;
    if(isBirthday) {
        baseSpeed = speed - 5;
    } else {
        baseSpeed = speed;
    }

    if(baseSpeed <= 60) {
        return 0; // no ticket
    } else if(baseSpeed > 60 && baseSpeed <= 80) {
        return 1; // small ticket
    } else {
        return 2; // big ticket
    }
}

