public String zipZap(String str) {
    String result = "";
    boolean zip = false;

    for (int i = 0; i < str.length(); i++) {
        char current = str.charAt(i);
        if (current == 'z') {
            zip = true;
        } else if (current == 'p' && zip) {
            result += "p";
            zip = false;
        } else if (zip) {
            i++;
            zip = false;
        } else {
            result += current;
        }
    }

    return result;
}

