            // If on vacation, alarm rings at 10:00
            return "10:00";
        } else {
            // If not on vacation, alarm rings at 7:00
            return "7:00";
        }
    } else {
        // Weekends
        if (vacation) {
            // If on vacation, alarm is off
            return "off";
        } else {
            // If not on vacation, alarm rings at 10:00
            return "10:00";
        }
    }
}

