public int makeChocolate(int small, int big, int goal) {
    int bigNeeded = goal / 5;
    int smallNeeded = goal % 5;

    while (bigNeeded > big) {
        bigNeeded--;
        smallNeeded += 5;
    }

    if (smallNeeded <= small && bigNeeded <= big) {
        return smallNeeded;
    }
    return -1;
}

