Code:
public int[] shiftLeft(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int[] shiftedArray = new int[nums.length];
    shiftedArray[0] = nums[1];
    shiftedArray[shiftedArray.length - 1] = nums[0];

    for (int i = 1; i < shiftedArray.length - 1; i++) {
        shiftedArray[i] = nums[i + 1];
    }

    return shiftedArray;
}

