public int[] fix45(int[] nums) {
    int start = 0;
    int end = nums.length - 1;

    while (start < end) {
        // Find first non-4 from start
        while (start < nums.length && nums[start] == 4) start++;
        // Find first non-5 from end
        while (end > 0 && nums[end] == 5) end--;
        // Swap if start is ahead of end
        if (start < end) {
            int temp = nums[start];
            nums[start] = nums[end];
            nums[end] = temp;
        }
    }
    return nums;
}

