public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int prev = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0 && nums[i] != prev) {
            prev = nums[i];
        } else if (nums[i] % 10 != 0) {
            nums[i] = prev;
        }
    }

    return nums;
}

public int sum67(int[] nums) {
    int sum = 0;
    boolean addToSum = true;

    for (int num : nums) {
        if (num == 6) {
            addToSum = false;
        } else if (num == 7) {
            addToSum = true;
        } else {
            if (addToSum) {
                sum += num;
            }
        }
    }

    return sum;
}

