    if (str.length() == 0) {
        return "@@";
    } else if (str.length() == 1) {
        return str + "@";
    } else {
        return str.substring(0, 2);
    }
}

public String repeatEnd(String str, int n) {
    if (n == 0) return "";
    if (n > str.length()) n = str.length();
    return str.substring(str.length() - n) + repeatEnd(str, n - 1);
}

