public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0, right = 0;

    while (right < n) {
        if (nums[right] == 5) {
            while (left < right && nums[left] != 4) {
                left++;
            }

            if (left == right) {
                int temp = nums[right];
                nums[right] = nums[right + 1];
                nums[right + 1] = temp;
                right++;
            } else {
                left++;
                right++;
            }
        } else {
            right++;
        }
    }

    return nums;
}

public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int prev = nums[0];

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0 && nums[i] != prev) {
            prev = nums[i];
        } else if (nums[i] % 10 != 0) {
            nums[i] = prev;
        }
    }

    return nums;
}

public int centeredAverage(int[] nums) {
    int min = nums[0];
    int max = nums[0];
    int sum = 0;
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] < min) {
            min = nums[i];
        }
        if (nums[i] > max) {
            max = nums[i];
        }
        sum += nums[i];
    }
    return (sum - min - max) / (nums.length - 2);
}

