    for (int num : nums) {
        if (num == 2 && previousNum != 2) {
            int count = 1;
            for (int i = 1; i < nums.length; i++) {
                if (nums[i] == 2 && nums[i - 1] == 2) {
                    count++;
                } else {
                    break;
                }
            }
            if (count % 2 != 0) {
                return false;
            }
        }
        previousNum = num;
    }
    return true;
}

