public int sum13(int[] nums) {
    int sum = 0;
    boolean isAfterThirteen = false;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 13) {
            isAfterThirteen = true;
        } else if (!isAfterThirteen) {
            sum += nums[i];
            isAfterThirteen = false;
        } else {
            isAfterThirteen = false;
        }
    }

    return sum;
}

