public int[] fix45(int[] nums) {
    int i = 0, j = 0;

    while (j < nums.length) {
        if (nums[j] != 4) {
            j++;
            continue;
        }

        while (i < j && nums[i] != 5) {
            i++;
        }

        // Swap 5 with 4 if i < j and i < nums.length
        if (i < j && i < nums.length) {
            int temp = nums[j];
            nums[j] = nums[i];
            nums[i] = temp;
        }

        i = j + 1;
        j++;
    }

    return nums;
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int[] res = new int[n];
    int i = 0, j = 0, k = 0;
    while (i < n) {
        if (nums[i] == 4) {
            res[j++] = nums[i];
            while (k < n && nums[k] != 5) {
                res[j++] = nums[k];
                k++;
            }
            res[j++] = nums[k++];
        } else {
            res[j++] = nums[i];
        }
        i++;
    }
    return res;
}

