public boolean xyzThere(String str) {
    int idx = 0;
    while (idx < str.length()) {
        if (str.charAt(idx) == 'x' && idx + 2 < str.length() && str.charAt(idx + 2) == 'z') {
            if (idx == 0 || str.charAt(idx - 1) != '.') {
                return true;
            }
        }
        idx++;
    }
    return false;
}

