public int makeChocolate(int small, int big, int goal) {
    if (big * 5 > goal) {
        if ((goal - big * 5) > small) {
            return -1;
        } else {
            return goal - big * 5;
        }
    } else {
        if (goal > (small + big * 5)) {
            return -1;
        } else {
            return goal % 5;
        }
    }
}

