        } else {
            nums[i] = currentMultiple;
        }
    }

    return nums;
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int[] ans = new int[n];
    int j = 0;
    for (int i = 0; i < n; i++) {
        if (nums[i] != 4) {
            ans[j++] = nums[i];
        }
    }
    for (int i = 0; i < n; i++) {
        if (nums[i] == 4) {
            ans[j++] = 5;
            ans[j++] = 4;
        }
    }
    return ans;
}

